SELECT sum(recharge_amount) FROM eb_user_shopping_credits_record
where uid = #{userId} and mer_id = #{merId}
and link_type = 'recharge'

SELECT sum(gift_amount) FROM eb_user_shopping_credits_record
where uid = #{userId} and mer_id = #{merId}
  and link_type = 'recharge'

SELECT sum(recharge_amount + gift_amount) FROM eb_user_shopping_credits_record
where uid = #{userId} and mer_id = #{merId}
  and link_type = 'order'
